     1|/**
     2| * IVX Proof-First Execution Framework — Evidence Gate
     3| *
     4| * Enforces that every technical claim in an IVX response is backed by real
     5| * tool-execution evidence. Blocks/categorises claims without evidence, adds
     6| * mandatory evidence metadata, separates internal audit streams from
     7| * user-visible chat, and enforces hard prohibitions (no simulated data
     8| * presented as real, no UUIDs as Git SHAs, no fake diffs, no deployment
     9| * claims without provider confirmation, no code-change claims without actual
    10| * diff output).
    11| *
    12| * Every public function is pure + deterministic (no I/O, network, or AI)
    13| * so the gate is fully unit-testable.
    14| */
    15|
    16|// ---------------------------------------------------------------------------
    17|// Output labels (requirement 3)
    18|// ---------------------------------------------------------------------------
    19|
    20|export const EVIDENCE_LABEL = {
    21|  /** No tool was run at all — the claim has zero backing evidence. */
    22|  NOT_EXECUTED: 'NOT EXECUTED',
    23|  /** A tool was run but its evidence output is unavailable / unreadable. */
    24|  UNVERIFIED: 'UNVERIFIED',
    25|  /** The answer contains generated / example / placeholder data. */
    26|  SIMULATED: 'SIMULATED',
    27|  /** A real tool ran and produced confirmable evidence. */
    28|  EXECUTED: 'EXECUTED',
    29|  /** Evidence was captured but could not be independently re-verified. */
    30|  EVIDENCE_UNAVAILABLE: 'EVIDENCE UNAVAILABLE',
    31|} as const;
    32|
    33|export type EvidenceLabel = (typeof EVIDENCE_LABEL)[keyof typeof EVIDENCE_LABEL];
    34|
    35|/**
    36| * The four canonical, owner-facing classification labels (TASK 2).
    37| * Every technical response is reduced to exactly ONE of these:
    38| *  - VERIFIED      = real evidence exists for the claim.
    39| *  - UNVERIFIED    = a tool ran but evidence is missing/unreadable.
    40| *  - NOT EXECUTED  = no execution occurred at all.
    41| *  - SIMULATED     = generated / example data, not a live result.
    42| */
    43|export const EVIDENCE_CLASSIFICATION = {
    44|  VERIFIED: 'VERIFIED',
    45|  UNVERIFIED: 'UNVERIFIED',
    46|  NOT_EXECUTED: 'NOT EXECUTED',
    47|  SIMULATED: 'SIMULATED',
    48|} as const;
    49|
    50|export type EvidenceClassification =
    51|  (typeof EVIDENCE_CLASSIFICATION)[keyof typeof EVIDENCE_CLASSIFICATION];
    52|
    53|/**
    54| * Reduce an internal gate result to one of the four owner-facing
    55| * classification labels (TASK 2 — "Every technical response must be
    56| * classified"). The internal EXECUTED / EVIDENCE_UNAVAILABLE labels map to
    57| * the owner-facing VERIFIED / UNVERIFIED vocabulary.
    58| *
    59| * Pure function — deterministic.
    60| */
    61|export function classifyTechnicalResponse(gateResult: EvidenceGateResult): EvidenceClassification {
    62|  switch (gateResult.overallLabel) {
    63|    case EVIDENCE_LABEL.EXECUTED:
    64|      return EVIDENCE_CLASSIFICATION.VERIFIED;
    65|    case EVIDENCE_LABEL.SIMULATED:
    66|      return EVIDENCE_CLASSIFICATION.SIMULATED;
    67|    case EVIDENCE_LABEL.UNVERIFIED:
    68|    case EVIDENCE_LABEL.EVIDENCE_UNAVAILABLE:
    69|      return EVIDENCE_CLASSIFICATION.UNVERIFIED;
    70|    case EVIDENCE_LABEL.NOT_EXECUTED:
    71|    default:
    72|      return EVIDENCE_CLASSIFICATION.NOT_EXECUTED;
    73|  }
    74|}
    75|
    76|/**
    77| * Whether an answer makes any technical claim at all (code/commit/deploy/
    78| * db/test). Non-technical chat (greetings, explanations) is not gated.
    79| *
    80| * Pure function.
    81| */
    82|export function isTechnicalResponse(answer: string): boolean {
    83|  return extractClaims(answer).length > 0;
    84|}
    85|
    86|// ---------------------------------------------------------------------------
    87|// Claim types the gate inspects (requirement 1)
    88|// ---------------------------------------------------------------------------
    89|
    90|export const CLAIM_CATEGORY = {
    91|  CODE_CHANGE: 'code_change',
    92|  GIT_COMMIT: 'git_commit',
    93|  DEPLOYMENT: 'deployment',
    94|  DATABASE_MUTATION: 'database_mutation',
    95|  API_RESULT: 'api_result',
    96|  TEST_RESULT: 'test_result',
    97|  FILE_WRITE: 'file_write',
    98|  PRODUCTION_VERIFICATION: 'production_verification',
    99|} as const;
   100|
   101|export type ClaimCategory = (typeof CLAIM_CATEGORY)[keyof typeof CLAIM_CATEGORY];
   102|
   103|// ---------------------------------------------------------------------------
   104|// Evidence metadata (requirement 2)
   105|// ---------------------------------------------------------------------------
   106|
   107|export type EvidenceMetadata = {
   108|  /** The tool/service that generated the evidence. */
   109|  toolName: string;
   110|  /** Unique request/trace/job identifier. */
   111|  requestId: string;
   112|  /** ISO-8601 timestamp of evidence capture. */
   113|  timestamp: string;
   114|  /** Reference to the raw tool output (file path, API response key, etc.). */
   115|  rawOutputRef: string;
   116|  /** The evidence label assigned after gate evaluation. */
   117|  label: EvidenceLabel;
   118|};
   119|
   120|export type EvidenceClaim = {
   121|  /** What the response text claims happened. */
   122|  category: ClaimCategory;
   123|  /** The claim text snippet extracted from the answer. */
   124|  claimedText: string;
   125|  /** Whether the claim is backed by real evidence. */
   126|  evidencePresent: boolean;
   127|  /** Evidence metadata (populated only when evidence exists). */
   128|  metadata: EvidenceMetadata | null;
   129|  /** The resulting label. */
   130|  label: EvidenceLabel;
   131|  /** Human-readable reason for the label. */
   132|  reason: string;
   133|};
   134|
   135|// ---------------------------------------------------------------------------
   136|// Hard prohibitions (requirement 4) — compiled detector patterns
   137|// ---------------------------------------------------------------------------
   138|
   139|const UUID_REGEX = /\b[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}\b/gi;
   140|const GIT_SHA_REGEX = /\b[0-9a-f]{7,40}\b/gi;
   141|const DEPLOY_REGEX = /\b(deploy(?:ed|ment)?|live|shipped|pushed to production|in production now|production build)\b/i;
   142|const COMMIT_REGEX = /\b(committed|commits?|pushed to (?:main|master|github)|merged)\b/i;
   143|const CODE_CHANGE_REGEX = /\b(changed|modified|updated|created|added|removed|refactored|patched|fixed)\s+(?:the |a )?(?:file|code|function|module|component|route|endpoint|screen|service|API)\b/i;
   144|const DB_MUTATION_REGEX = /\b(inserted|updated|deleted|migrated|seeded|upserted|created table|altered table|ran (?:a |the )?migration|executed SQL)\b/i;
   145|const TEST_RESULT_REGEX = /\b(\d+\/\d+\s+(?:tests?\s+)?(?:pass|fail|green)|all tests pass|test suite (?:pass|green|succeeded)|bun test.*(?:pass|fail))\b/i;
   146|
   147|// Matches claims that look like they cite a commit hash but are actually UUIDs.
   148|const UUID_AS_SHA_REGEX = /\b(?:commit|SHA|hash)[:\s]*([0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12})\b/i;
   149|
   150|// Matches generated/fake diff output patterns.
   151|const FAKE_DIFF_REGEX = /\b(?:---\s+\+\+\+|@@\s+[-+]\d+,\d+\s+[-+]\d+,\d+\s+@@)\b/i;
   152|
   153|// ---------------------------------------------------------------------------
   154|// Fake-deliverable detectors (no report-file/link/storage tool exists in IVX)
   155|// ---------------------------------------------------------------------------
   156|
   157|// A markdown link whose href is a dead placeholder: "#", "#anchor", empty,
   158|// javascript:void(0), or about:blank — e.g. "[Access Buyer and JV Report](#)".
   159|const PLACEHOLDER_LINK_REGEX = /\[[^\]]+\]\(\s*(?:#[\w-]*|javascript:\s*void\(0\)|about:blank|)\s*\)/i;
   160|
   161|// A markdown link whose href is an obvious example/placeholder host.
   162|const PLACEHOLDER_HREF_REGEX = /\[[^\]]+\]\(\s*(?:https?:\/\/)?(?:example\.(?:com|org|net)|localhost|127\.0\.0\.1|your-?(?:domain|site|link|url)|placeholder|tbd|todo)\b[^)]*\)/i;
   163|
   164|// Claims that a report/file/deliverable is ready/finalized/generated/attached.
   165|const DELIVERABLE_READY_REGEX = /\b(report|file|document|export|pdf|spreadsheet|deliverable|download|link)\s+(?:is\s+)?(?:now\s+)?(?:ready|complete[d]?|finali[sz]ed|generated|available|attached|created|prepared)\b|\b(?:here(?:'s| is)|attached is|i(?:'ve| have)\s+(?:created|generated|prepared|finished))\b[^.\n]{0,40}\b(report|file|document|export|pdf|spreadsheet|deliverable|link|download)\b/i;
   166|
   167|// Deferred-delivery promises: "I'll deliver shortly", "give me 30 more minutes".
   168|const DEFERRED_DELIVERY_REGEX = /\b(?:i(?:'ll| will| am going to)|we(?:'ll| will)|let me|give me|need|in)\b[^.\n]{0,48}\b(?:provide|deliver|send|share|generate|finish|complete|have|prepare)\b[^.\n]{0,48}\b(?:link|report|file|document|shortly|soon|in a (?:few|couple)|\d+\s*(?:more\s*)?(?:minutes?|hours?|mins?))\b/i;
   169|
   170|// Live-query narrative: the model claiming it is running / about to run a SQL
   171|// or database query mid-message. A text model cannot execute queries itself —
   172|// real counts come only from the IVX count tool. These phrases are fabricated
   173|// unless a real query actually ran in this turn.
   174|const QUERY_NARRATIVE_REGEXES: RegExp[] = [
   175|  /\bi(?:'m| am)\s+(?:now\s+)?(?:running|executing|performing|querying)\b[^.\n]{0,40}\b(?:quer(?:y|ies)|sql|count|database|table)\b/i,
   176|  /\b(?:running|executing|performing)\s+(?:these|the|a|an|those)?\s*quer(?:y|ies)\s+(?:now|right now)\b/i,
   177|  /\b(?:let me|i'?ll|i will|i'?m going to|going to|allow me to)\s+(?:run|execute|perform|query|pull)\b[^.\n]{0,40}\b(?:quer(?:y|ies)|sql|count|database|table|investors?|buyers?|deals?)\b/i,
   178|  /\bi'?ll\s+(?:run|execute)\s+(?:a|an|the)?\s*(?:count\s*)?quer(?:y|ies)\b/i,
   179|  /\b(?:querying|running a query on|i(?:'m| am) querying)\s+the\b[^.\n]{0,30}\btable\b/i,
   180|];
   181|
   182|// Open-ended time promise near deliverable language.
   183|// NOTE: A bare numeric time like "27 minutes" is NOT a delivery promise — it is
   184|// a factual elapsed-time statement (e.g. "booted 27 minutes ago", "27 minutes
   185|// since last check"). The promise signal is the modifier "more" ("30 more
   186|// minutes") or an explicit "in a few minutes" / "shortly" / "almost done".
   187|// Matching bare numbers hijacked legitimate senior-developer answers that quote
   188|// uptime/elapsed time, rewriting them to REPORT NOT READY. The bare-number arm
   189|// now requires the "more" modifier so factual elapsed-time facts pass through.
   190|const TIME_PROMISE_REGEX = /\b(?:\d+\s*more\s*(?:minutes?|hours?|mins?)|shortly|in a moment|in a (?:few|couple)\s+(?:minutes?|hours?)|almost (?:done|finished|ready|complete)|just a (?:bit|moment|sec))\b/i;
   191|
   192|// Deliverable context: a NOUN (a report/file/export artifact), not the verb
   193|// "report" (as in "I'll report the commit"). The verb form is excluded by
   194|// requiring the noun stem to be preceded by a determiner/adjective OR to be a
   195|// standalone noun. This stops "report the current commit" from being treated as
   196|// a deliverable claim.
   197|const DELIVERABLE_CONTEXT_REGEX = /\b(?:a|an|the|this|that|your|our|my)\s+(?:report|file|document|export|pdf|spreadsheet|deliverable|link|download)\b|\b(?:report|file|document|export|pdf|spreadsheet|deliverable|link|download)\s+(?:is|are|was|were|has|have|will|should|can|may)\b|\bdeliver(?:ing|s|ed)?|finish(?:ing|es|ed)?|generat(?:ing|es|ed)|finali[sz](?:ing|es|ed)\b/i;
   198|
   199|// ---------------------------------------------------------------------------
   200|// Prohibition scanner (requirement 4 + requirement 6)
   201|// ---------------------------------------------------------------------------
   202|
   203|export type ProhibitionViolation = {
   204|  rule: string;
   205|  snippet: string;
   206|  reason: string;
   207|};
   208|
   209|/**
   210| * Scan an answer string for hard-prohibition violations.
   211| * Pure function — no I/O, always returns the same result for the same input.
   212| */
   213|export function scanForProhibitions(answer: string, evidenceAvailable: boolean): ProhibitionViolation[] {
   214|  const violations: ProhibitionViolation[] = [];
   215|
   216|  // 1. Simulated data presented as real
   217|  if (!evidenceAvailable) {
   218|    // Check for commit claims when there's no evidence of a real commit
   219|    const commitMatch = COMMIT_REGEX.exec(answer);
   220|    if (commitMatch) {
   221|      violations.push({
   222|        rule: 'NO_SIMULATED_DATA_AS_REAL',
   223|        snippet: commitMatch[0],
   224|        reason: 'Claims a commit was made but no commit evidence (github.commitSha) exists.',
   225|      });
   226|    }
   227|
   228|    // Check for deploy claims without deployment evidence
   229|    const deployMatch = DEPLOY_REGEX.exec(answer);
   230|    if (deployMatch) {
   231|      violations.push({
   232|        rule: 'NO_SIMULATED_DATA_AS_REAL',
   233|        snippet: deployMatch[0],
   234|        reason: 'Claims deployment was performed but no deployment evidence (render.deployId) exists.',
   235|      });
   236|    }
   237|
   238|    // Check for code-change claims without changed-files evidence
   239|    const codeMatch = CODE_CHANGE_REGEX.exec(answer);
   240|    if (codeMatch) {
   241|      violations.push({
   242|        rule: 'NO_SIMULATED_DATA_AS_REAL',
   243|        snippet: codeMatch[0],
   244|        reason: 'Claims code was changed but no changedFiles evidence exists.',
   245|      });
   246|    }
   247|
   248|    // Check for database mutation claims without DB evidence
   249|    const dbMatch = DB_MUTATION_REGEX.exec(answer);
   250|    if (dbMatch) {
   251|      violations.push({
   252|        rule: 'NO_SIMULATED_DATA_AS_REAL',
   253|        snippet: dbMatch[0],
   254|        reason: 'Claims a database mutation was performed but no DB-operation evidence exists.',
   255|      });
   256|    }
   257|  }
   258|
   259|  // 2. UUID presented as Git SHA
   260|  const uuidShaMatch = UUID_AS_SHA_REGEX.exec(answer);
   261|  if (uuidShaMatch) {
   262|    violations.push({
   263|      rule: 'NO_UUID_AS_GIT_SHA',
   264|      snippet: uuidShaMatch[0],
   265|      reason: `A UUID (${uuidShaMatch[1]}) is presented as a Git commit SHA.`,
   266|    });
   267|  }
   268|
   269|  // Now check non-UUID-format strings: if evidence is absent and the answer contains
   270|  // a GitHub-format hex string but the caller's evidence has no real SHA,
   271|  // that's also a violation.
   272|  if (!evidenceAvailable) {
   273|    const shaMatches = answer.matchAll(GIT_SHA_REGEX);
   274|    for (const match of shaMatches) {
   275|      const sha = match[0];
   276|      // Skip if it's clearly something else (like a UUID or a hex color in a non-commit context)
   277|      if (sha.length >= 7 && !uuidShaMatch && /\bcommit\b/i.test(answer.slice(Math.max(0, match.index! - 40), match.index! + sha.length + 10))) {
   278|        violations.push({
   279|          rule: 'NO_FAKE_GIT_SHA',
   280|          snippet: sha,
   281|          reason: 'A hex string resembling a Git SHA appears near commit language but no real commit evidence exists.',
   282|        });
   283|        break; // One is enough — don't flood
   284|      }
   285|    }
   286|  }
   287|
   288|  // 3. Deployment claim without provider confirmation
   289|  if (!evidenceAvailable) {
   290|    const deployWithProvider = /\b(Render|Vercel|AWS|Cloudflare|Netlify|Heroku)\s+(?:deploy|auto-deploy|build)/i.exec(answer);
   291|    if (deployWithProvider) {
   292|      violations.push({
   293|        rule: 'NO_DEPLOY_WITHOUT_PROVIDER_CONFIRMATION',
   294|        snippet: deployWithProvider[0],
   295|        reason: 'References a provider deployment but has no deploy confirmation evidence.',
   296|      });
   297|    }
   298|  }
   299|
   300|  // 4. Code change claimed without actual diff output
   301|  const diffMatch = FAKE_DIFF_REGEX.exec(answer);
   302|  if (diffMatch && !evidenceAvailable) {
   303|    violations.push({
   304|      rule: 'NO_CODE_CHANGE_WITHOUT_DIFF',
   305|      snippet: diffMatch[0],
   306|      reason: 'Contains diff-like syntax but no actual diff evidence exists.',
   307|    });
   308|  }
   309|
   310|  return violations;
   311|}
   312|
   313|// ---------------------------------------------------------------------------
   314|// Fake-deliverable scanner (no report-file/link/storage tool exists)
   315|// ---------------------------------------------------------------------------
   316|
   317|/**
   318| * Scan an answer for fake-deliverable claims:
   319| *  - placeholder / dead links (href "#", empty, void, example.com, localhost)
   320| *  - "report/file is ready/finalized/generated" with no real deliverable
   321| *  - deferred-delivery promises ("I'll deliver shortly", "30 more minutes")
   322| *
   323| * `hasRealDeliverable` is true ONLY when a real, attributable deliverable
   324| * (a reachable hosted file/link or a stored file reference) actually exists.
   325| * Placeholder/dead links are ALWAYS blocked regardless, because a real link
   326| * is never "#". IVX currently has no report-file-generation or file-hosting
   327| * tool, so `hasRealDeliverable` is false unless a caller proves otherwise.
   328| *
   329| * Pure function — deterministic, no I/O.
   330| */
   331|export function scanForFakeDeliverableClaims(
   332|  answer: string,
   333|  hasRealDeliverable: boolean,
   334|): ProhibitionViolation[] {
   335|  const violations: ProhibitionViolation[] = [];
   336|
   337|  const placeholder = PLACEHOLDER_LINK_REGEX.exec(answer);
   338|  if (placeholder) {
   339|    violations.push({
   340|      rule: 'NO_PLACEHOLDER_LINK',
   341|      snippet: placeholder[0],
   342|      reason:
   343|        'Contains a non-functional placeholder link (href "#"/empty/void). A deliverable link must point to a real, reachable file.',
   344|    });
   345|  }
   346|
   347|  const placeholderHref = PLACEHOLDER_HREF_REGEX.exec(answer);
   348|  if (placeholderHref) {
   349|    violations.push({
   350|      rule: 'NO_PLACEHOLDER_LINK',
   351|      snippet: placeholderHref[0],
   352|      reason:
   353|        'Contains a placeholder/example href (example.com / localhost / your-domain / TBD). Not a real deliverable.',
   354|    });
   355|  }
   356|
   357|  if (!hasRealDeliverable) {
   358|    const ready = DELIVERABLE_READY_REGEX.exec(answer);
   359|    if (ready) {
   360|      violations.push({
   361|        rule: 'NO_DELIVERABLE_WITHOUT_REAL_FILE',
   362|        snippet: ready[0],
   363|        reason:
   364|          'Claims a report/file/deliverable is ready but no real file or reachable link exists. IVX has no report-file-generation or file-hosting tool — return a VERIFIED failure reason instead.',
   365|      });
   366|    }
   367|
   368|    const deferred = DEFERRED_DELIVERY_REGEX.exec(answer);
   369|    if (deferred) {
   370|      violations.push({
   371|        rule: 'NO_UNFULFILLED_DELIVERY_PROMISE',
   372|        snippet: deferred[0],
   373|        reason:
   374|          'Promises a future deliverable ("will deliver / X more minutes / shortly") with no tracked job state. Either deliver now or return a VERIFIED failure reason.',
   375|      });
   376|    }
   377|
   378|    const timePromise = TIME_PROMISE_REGEX.exec(answer);
   379|    if (timePromise && DELIVERABLE_CONTEXT_REGEX.test(answer)) {
   380|      violations.push({
   381|        rule: 'NO_TIME_PROMISE',
   382|        snippet: timePromise[0],
   383|        reason:
   384|          'Open-ended time promise ("30 more minutes / shortly / almost done") for a deliverable with no tracked job. Not allowed.',
   385|      });
   386|    }
   387|  }
   388|
   389|  return violations;
   390|}
   391|
   392|/**
   393| * Scan an answer for fabricated live-query narrative — phrases that claim a SQL /
   394| * database query is being run mid-message when no real query actually executed
   395| * in this turn. A text model cannot run queries itself; real counts come only
   396| * from the IVX count tool. When `realQueryRan` is true (the count tool executed
   397| * a real query this turn), this narrative is legitimate and is not flagged.
   398| *
   399| * Pure function — deterministic, no I/O.
   400| */
   401|export function scanForUnbackedQueryNarrative(answer: string, realQueryRan: boolean): ProhibitionViolation[] {
   402|  if (realQueryRan) return [];
   403|  for (const regex of QUERY_NARRATIVE_REGEXES) {
   404|    const match = regex.exec(answer);
   405|    if (match) {
   406|      return [
   407|        {
   408|          rule: 'NO_QUERY_NARRATIVE_WITHOUT_EXECUTION',
   409|          snippet: match[0],
   410|          reason:
   411|            'Claims a database/SQL query is being run mid-message, but no real query executed this turn. A text model cannot run queries — use the IVX count tool or state the real number is unavailable.',
   412|        },
   413|      ];
   414|    }
   415|  }
   416|  return [];
   417|}
   418|
   419|/**
   420| * The honest message IVX returns when it tried to narrate running a query but no
   421| * real query executed. Used to rewrite fabricated "I'm running these queries
   422| * now" answers on the chat path.
   423| */
   424|export function buildNoLiveQueryMessage(): string {
   425|  return [
   426|    'I do not have a live count for that right now.',
   427|    '',
   428|    "I can't run a database query inside this reply, and the count tool did not return a verified number this turn (Supabase may be unconfigured, or the table may not exist in this project). Rather than give you a fabricated figure, I'm telling you straight: no exact count is available right now.",
   429|    '',
   430|    'Ask again and I will run a real count=exact query, or tell me the exact table to count.',
   431|  ].join('\n');
   432|}
   433|
   434|// ---------------------------------------------------------------------------
   435|// Claim extraction (requirement 1 — identify what the answer claims)
   436|// ---------------------------------------------------------------------------
   437|
   438|export type ExtractedClaim = {
   439|  category: ClaimCategory;
   440|  claimedText: string;
   441|};
   442|
   443|/**
   444| * Extract the technical claims present in an answer string.
   445| * Pure function — deterministic, no side effects.
   446| */
   447|export function extractClaims(answer: string): ExtractedClaim[] {
   448|  const claims: ExtractedClaim[] = [];
   449|
   450|  for (const match of answer.matchAll(new RegExp(CODE_CHANGE_REGEX.source, 'gi'))) {
   451|    claims.push({ category: CLAIM_CATEGORY.CODE_CHANGE, claimedText: match[0] });
   452|  }
   453|
   454|  for (const match of answer.matchAll(new RegExp(COMMIT_REGEX.source, 'gi'))) {
   455|    claims.push({ category: CLAIM_CATEGORY.GIT_COMMIT, claimedText: match[0] });
   456|  }
   457|
   458|  for (const match of answer.matchAll(new RegExp(DEPLOY_REGEX.source, 'gi'))) {
   459|    claims.push({ category: CLAIM_CATEGORY.DEPLOYMENT, claimedText: match[0] });
   460|  }
   461|
   462|  for (const match of answer.matchAll(new RegExp(DB_MUTATION_REGEX.source, 'gi'))) {
   463|    claims.push({ category: CLAIM_CATEGORY.DATABASE_MUTATION, claimedText: match[0] });
   464|  }
   465|
   466|  for (const match of answer.matchAll(new RegExp(TEST_RESULT_REGEX.source, 'gi'))) {
   467|    claims.push({ category: CLAIM_CATEGORY.TEST_RESULT, claimedText: match[0] });
   468|  }
   469|
   470|  return claims;
   471|}
   472|
   473|// ---------------------------------------------------------------------------
   474|// Evidence gate evaluation (requirement 1)
   475|// ---------------------------------------------------------------------------
   476|
   477|export type EvidenceGateResult = {
   478|  /** Whether the answer passes the evidence gate (no unbacked claims). */
   479|  passed: boolean;
