   564|  // Overall label: strongest claim label (worst-first priority)
   565|  const overallLabel = hasClaims
   566|    ? evidenceClaims.some((c) => c.label === EVIDENCE_LABEL.NOT_EXECUTED)
   567|      ? EVIDENCE_LABEL.NOT_EXECUTED
   568|      : evidenceClaims.some((c) => c.label === EVIDENCE_LABEL.UNVERIFIED)
   569|        ? EVIDENCE_LABEL.UNVERIFIED
   570|        : evidenceClaims.some((c) => c.label === EVIDENCE_LABEL.SIMULATED)
   571|          ? EVIDENCE_LABEL.SIMULATED
   572|          : EVIDENCE_LABEL.EXECUTED
   573|    : toolWasExecuted
   574|      ? EVIDENCE_LABEL.EXECUTED
   575|      : EVIDENCE_LABEL.NOT_EXECUTED;
