   581|    `Overall: ${overallLabel}`,
   582|    `Tool executed: ${toolWasExecuted}`,
   583|    `Repo verified: ${repoAccessVerified}`,
   584|  ].join(' | ');
   585|
   586|  return { passed, claims: evidenceClaims, violations, overallLabel, summary };
   587|}
